3	/**
4	 * Row-level scope enforcement middleware.
5	 *
6	 * For Host role: restricts data to assigned station_id(s).
7	 * For Platform Ops: no filter (cross-site visibility).
8	 * For Guest: no station-scoped data is accessible.
9	 *
10	 * Attaches ctx.state.stationScope with the relevant station IDs,
11	 * or null if no filtering is needed (platform_ops).
12	 */
13	function scopeFilter() {
14	  return async (ctx, next) => {
15	    const user = ctx.state.user;
16	
17	    if (!user) {
18	      // Guest/unauthenticated - no station scope
19	      ctx.state.stationScope = null;
20	      await next();
21	      return;
22	    }
23	
24	    if (user.role === 'platform_ops') {
25	      // Cross-site visibility, no filtering
26	      ctx.state.stationScope = null;
27	    } else if (user.role === 'host') {
28	      // Filter by assigned stations
29	      const stationIds = user.assignedStationIds || [];
30	      if (stationIds.length === 0) {
31	        throw createError(403, 'FORBIDDEN', 'You have no station assignments. Contact an administrator.');
32	      }
33	      ctx.state.stationScope = stationIds;
34	    } else {
35	      ctx.state.stationScope = null;
36	    }
37	
38	    await next();
39	  };
40	}
41	
42	/**
43	 * Apply station scope filter to a knex query builder.
44	 * @param {Object} query - Knex query builder
45	 * @param {Array|null} stationScope - Array of station IDs or null for no filter
46	 * @param {string} column - Column name to filter on (default: 'station_id')
47	 * @returns {Object} - Modified query builder
48	 */
49	function applyStationScope(query, stationScope, column = 'station_id') {
50	  if (stationScope && stationScope.length > 0) {
51	    return query.whereIn(column, stationScope);
52	  }
53	  return query;
54	}
