6	/**
7	 * Extract session token: HttpOnly cookie first, then Bearer header fallback.
8	 */
9	function extractToken(ctx) {
10	  // 1. Try HttpOnly session cookie (preferred, secure transport)
11	  const cookieToken = ctx.cookies.get(SESSION_COOKIE);
12	  if (cookieToken) return cookieToken;
13	
14	  // 2. Fallback to Bearer Authorization header (API/migration compatibility)
15	  const header = ctx.headers.authorization;
16	  if (!header) return null;
17	  const parts = header.split(' ');
18	  if (parts.length !== 2 || parts[0] !== 'Bearer') return null;
19	  const token = parts[1].trim();
20	  return token || null;
21	}
22	
23	/**
24	 * Look up session by token (session.id = token), validate expiry, return user.
25	 */
26	async function resolveSession(token) {
27	  const tokenHash = crypto.createHash('sha256').update(token).digest('hex');
28	  const session = await db('sessions')
29	    .where('id', tokenHash)
30	    .first();
31	
32	  if (!session) return null;
33	
34	  // SECURITY: Reject pending_verification sessions — they cannot access authenticated routes
35	  if (session.state === 'pending_verification') {
36	    return null;
37	  }
38	
39	  const now = new Date();
40	
41	  // Hard expiry: 30 days
42	  if (session.expires_at && new Date(session.expires_at) < now) {
43	    return null;
44	  }
45	
46	  // Inactivity timeout: 8 hours
47	  const inactivityLimit = 8 * 60 * 60 * 1000;
48	  if (session.last_active_at && (now - new Date(session.last_active_at)) > inactivityLimit) {
49	    return null;
50	  }
51	
52	  // Auto-renew last_active_at
53	  await db('sessions')
54	    .where('id', tokenHash)
55	    .update({ last_active_at: now });
56	
57	  // Fetch user — role is ENUM directly on users table
58	  const user = await db('users')
59	    .where('id', session.user_id)
60	    .where('is_active', true)
61	    .select('id', 'username', 'display_name', 'phone_last4', 'role', 'is_active', 'max_sessions', 'created_at')
62	    .first();
63	
64	  if (!user) return null;
65	
66	  // Fetch assigned station IDs for host users
67	  let assignedStationIds = [];
68	  if (user.role === 'host') {
69	    const scopes = await db('user_station_scopes')
70	      .where('user_id', user.id)
71	      .select('station_id');
72	    assignedStationIds = scopes.map(s => s.station_id);
73	  }
74	
75	  return {
76	    session,
77	    user: {
78	      ...user,
79	      assignedStationIds
80	    }
81	  };
82	}
83	
84	/**
85	 * Required authentication middleware.
86	 */
87	function authenticate() {
88	  return async (ctx, next) => {
89	    const token = extractToken(ctx);
90	    if (!token) {
91	      ctx.status = 401;
92	      ctx.body = { success: false, error: { code: 'UNAUTHENTICATED', message: 'Authentication required. Provide a Bearer token.' } };
93	      return;
94	    }
95	
96	    const result = await resolveSession(token);
97	    if (!result) {
98	      ctx.status = 401;
99	      ctx.body = { success: false, error: { code: 'UNAUTHENTICATED', message: 'Session is invalid or expired.' } };
100	      return;
101	    }
102	
103	    ctx.state.user = result.user;
104	    ctx.state.session = result.session;
105	    ctx.state.token = token;
106	
107	    await next();
108	  };
109	}
110	
111	/**
112	 * Optional authentication middleware.
113	 */
114	function optionalAuth() {
115	  return async (ctx, next) => {
116	    const token = extractToken(ctx);
117	    if (token) {
118	      const result = await resolveSession(token);
119	      if (result) {
120	        ctx.state.user = result.user;
121	        ctx.state.session = result.session;
122	        ctx.state.token = token;
123	      }
124	    }
125	    await next();
126	  };
127	}
128	
129	/**
130	 * Role-based access control middleware.
131	 */
132	function requireRole(...roles) {
133	  return async (ctx, next) => {
134	    if (!ctx.state.user) {
135	      ctx.status = 401;
136	      ctx.body = { success: false, error: { code: 'UNAUTHENTICATED', message: 'Authentication required.' } };
137	      return;
138	    }
139	    if (!roles.includes(ctx.state.user.role)) {
140	      ctx.status = 403;
141	      ctx.body = { success: false, error: { code: 'FORBIDDEN', message: `Requires role: ${roles.join(', ')}.` } };
142	      return;
143	    }
144	    await next();
145	  };
146	}
147	
148	module.exports = { authenticate, optionalAuth, requireRole, extractToken, resolveSession };
