5	function errorHandler() {
6	  return async (ctx, next) => {
7	    try {
8	      await next();
9	    } catch (err) {
10	      const status = err.status || err.statusCode || 500;
11	      const code = err.code || 'INTERNAL_ERROR';
12	      const message = err.expose !== false && err.message ? err.message : 'An unexpected error occurred.';
13	
14	      ctx.status = status;
15	      ctx.body = {
16	        success: false,
17	        error: {
18	          code,
19	          message,
20	          ...(err.details ? { details: err.details } : {})
21	        }
22	      };
23	
24	      // Log 5xx errors to console
25	      if (status >= 500) {
26	        console.error(`[ERROR] ${status} ${code}: ${err.message}`);
27	        if (err.stack) console.error(err.stack);
28	      }
29	    }
30	  };
31	}
