33	/**
34	 * Create an application error with structured fields.
35	 */
36	function createError(status, code, message, details) {
37	  const err = new Error(message);
38	  err.status = status;
39	  err.code = code;
40	  err.expose = true;
41	  if (details) err.details = details;
