1	/**
2	 * In-memory rate limiter for DDoS protection at the route level.
3	 * Default: 5 attempts per 10-minute window per IP. Callers can override
4	 * both `windowMs` and `max` via the options object passed to rateLimiter().
5	 *
6	 * Note: Resets on server restart. The persistent brute-force lockout
7	 * (5 failed attempts / 10 min) is handled by authService via the
8	 * login_attempts DB table, which survives restarts.
9	 */
10	
11	const store = new Map();
12	
13	const WINDOW_MS = 10 * 60 * 1000; // 10 minutes
14	const MAX_ATTEMPTS = 5;
15	
16	/**
17	 * Clean up expired entries periodically.
18	 */
19	setInterval(() => {
20	  const now = Date.now();
21	  for (const [key, entry] of store) {
22	    if (now - entry.windowStart > WINDOW_MS) {
23	      store.delete(key);
24	    }
25	  }
26	}, 60 * 1000); // Cleanup every minute
27	
28	/**
29	 * Rate limiter middleware factory.
30	 * @param {Object} options
31	 * @param {number} options.windowMs - Window size in milliseconds (default: 10 min)
32	 * @param {number} options.max - Max attempts per window (default: 5)
33	 */
34	function rateLimiter(options = {}) {
35	  const windowMs = options.windowMs || WINDOW_MS;
36	  const max = options.max || MAX_ATTEMPTS;
37	
38	  return async (ctx, next) => {
39	    const ip = ctx.ip || ctx.request.ip || 'unknown';
40	    const now = Date.now();
41	
42	    let entry = store.get(ip);
43	
44	    if (!entry || (now - entry.windowStart > windowMs)) {
45	      entry = { windowStart: now, count: 0 };
46	      store.set(ip, entry);
47	    }
48	
49	    entry.count++;
50	
51	    if (entry.count > max) {
52	      const retryAfter = Math.ceil((entry.windowStart + windowMs - now) / 1000);
53	      ctx.set('Retry-After', String(retryAfter));
54	      ctx.status = 429;
55	      ctx.body = {
56	        success: false,
57	        error: {
58	          code: 'RATE_LIMITED',
59	          message: 'Too many requests. Please try again later.',
60	          retryAfterSeconds: retryAfter
61	        }
62	      };
63	      return;
64	    }
65	
66	    await next();
67	  };
68	}
69	
70	/**
71	 * Reset rate limit for a specific IP (e.g., after successful login).
72	 */
73	function resetRateLimit(ip) {
74	  store.delete(ip);
75	}
76	
77	module.exports = { rateLimiter, resetRateLimit };
